function glyph(name: string): IconComponent {
	function Glyph({ variant = "linear", className = "", ...rest }: IconProps) {
		const svg = (variant === "bold" ? BOLD[name] : LINEAR[name]) ?? LINEAR[name];
		return (
			<span
				className={`inline-flex shrink-0 ${className}`}
				role="img"
				aria-hidden="true"
				dangerouslySetInnerHTML={{ __html: svg }}
				{...rest}
			/>
		);
	}
	Glyph.displayName = name;
	return Glyph;
}

